async (params, browser) => {
  // Open page
  await browser.open(`${params.search_url}`)

  // Wait for content
  await browser.waitForSelector('.cl-search-result, .result-row, .cl-static-search-result, body', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const results = []; document.querySelectorAll('.cl-search-result, .result-row, .cl-static-search-result').forEach((el,i) => { if(i>=20) return; const titleEl = el.querySelector('a.posting-title, a.result-title, a.cl-app-anchor'); const priceEl = el.querySelector('.priceinfo, .result-price'); const imgEl = el.querySelector('img'); results.push({ title: titleEl?titleEl.textContent.trim():'', url: titleEl?titleEl.href:'', price: priceEl?priceEl.textContent.trim():'', thumbnail: imgEl?imgEl.src:'' }); }); return { result_count: results.length, results, url: window.location.href }`)

  return page_data
}
